/**
 * @summary List jobs for a tenant
 */
export const getListJobsUrl = (tenantId: number, params?: ListJobsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/tenants/${tenantId}/jobs?${stringifiedParams}`
    : `/api/tenants/${tenantId}/jobs`;
};

export const listJobs = async (
  tenantId: number,
  params?: ListJobsParams,
  options?: RequestInit,
): Promise<Job[]> => {
  return customFetch<Job[]>(getListJobsUrl(tenantId, params), {
    ...options,
    method: "GET",
  });
};

